import React, { useState } from "react";
import "./App.css";
import { array_of_mutants, Original, init } from "./mutants";

/*
                
    Komponens(function/class)  ->  JSX elemek  -> React -> DOM(HTML)
                       A       render                          |
           state változás <-------------------esemény----------      

*/

function ExtraHoliday() {
  var [eredmeny, setEredmeny] = useState("-");
  var [killedMutants, setKilledMutants] = useState("-");
  var [testCaseNumber, setNumber] = useState(0);
  var [killed] = useState([]);
  //var [wrongTests, setWrongTests] = useState('')
  var [wrongTests] = useState([]);
  var [printWrongTests, setPrintWrongTests] = useState("");
  var [missing, setMissing] = useState("");
  var [result, setResult] = useState("");
  var [mutant] = useState([]);
  var [wrongSolution, setWrongSolution] = useState(false);
  var [extraWork, setExtraWork] = useState(0);
  var [holidayNumber, setHoliday] = useState(0);
  // var [latenessNumber, setLateness] = useState(0);
  var [gameOver, setGameOver] = useState(false);
  var [freeLateness, setFreeLateness] = useState(false);

  var resultOrig;

  for (var i = 0; i < array_of_mutants.length; i++) {
    if (killed[i] === undefined) {
      killed[i] = false;
    }
  }

  if (wrongTests[0] === undefined) wrongTests[0] = "";

  function nextTest() {
    setExtraWork(0);
    setHoliday(0);
    //  setLateness(0);
    setEredmeny(0);
    setGameOver(false);
    setFreeLateness(false);
    init();
  }

  async function downloadTasks() {
    document.getElementById("downloader").click();
  }

  function tryAgain() {
    // window.location.href = '/'
    for (var i = 0; i < array_of_mutants.length; i++) {
      killed[i] = false;
    }
    nextTest();
    setNumber(0);
    setPrintWrongTests("");
    setResult("");
    setMissing("");
  }

  function callFunctions(operation) {
    var killedMutants1 = "";

    resultOrig = Original(
      extraWork,
      holidayNumber,
      gameOver,
      //  freeLateness,
      operation,
      0
    );

    var superfluousTest = true;
    var mutantResult = {
      //   extraWork: 0,
      //   holidayNumber: 0,
      //  mutant: "",
    };
    testCaseNumber++;
    for (var i = 0; i < array_of_mutants.length; i++) {
      if (!killed[i]) {
        mutantResult = array_of_mutants[i](
          extraWork,
          holidayNumber,
          gameOver,
          //       freeLateness,
          operation,
          i + 1
        );
        mutant[i] = mutantResult.mutant;

        if (
          +resultOrig.extraWork !== +mutantResult.extraWork ||
          +resultOrig.holidayNumber !== +mutantResult.holidayNumber ||
          resultOrig.gameOver !== mutantResult.gameOver
        ) {
          var j = i + 1;
          killedMutants1 = killedMutants1 + j + " ";
          killed[i] = true;
          mutant[i] = "";
          superfluousTest = false;
          console.log("killed mutant: ", i + 1);
        }
      }
    }
    extraWork = resultOrig.extraWork;
    holidayNumber = resultOrig.holidayNumber;
    gameOver = resultOrig.gameOver;
    freeLateness = resultOrig.freeLateness;

    setExtraWork(extraWork);
    setHoliday(holidayNumber);
    // setLateness(latenessNumber);
    setGameOver(gameOver);
    setKilledMutants(killedMutants1);
    setFreeLateness(freeLateness);
    setNumber(testCaseNumber);
  }

  function printResult() {
    var missingTests = false;
    var missedTestNumber = 0;

    for (var i = 0; i < array_of_mutants.length; i++) {
      if (!killed[i]) {
        missing = "Missing test: " + mutant[i]; //'Some necessary test cases are missing.'
        missingTests = true;
        missedTestNumber++;
        //   console.log('not killed ', i)
      }
    }
    var ratio =
      100 - Math.round((missedTestNumber / array_of_mutants.length) * 100);
    printWrongTests = wrongTests;
    setPrintWrongTests(printWrongTests);

    if (testCaseNumber === 0) {
      result = "Please write your test cases!";
      alert("Please write your test cases!");
      return;
    } else if (
      !missingTests //&&
      //   !wrongSolution &&
      //   testCaseNumber > optimalTestCaseNumber
    ) {
      result = "Congratulation, you are very good at test design!";
      missing = "---";
      setMissing(missing);
      //   } else if (!missingTests && testCaseNumber === optimalTestCaseNumber) {
    } else
      result =
        "You have found " + ratio + "% of the potential bugs. Try again! ";
    setResult(result);
    setMissing(missing);
  }

  return (
    <div className="App">
      <header className="Back-header">
        <p class="Back">
          <a href="https://test-design.org/practical-exercises/">
            Back to Test Design Exercises
          </a>
        </p>
      </header>

      <header className="App-header">
        {console.log("---------------------------")}
        <p class="exercise">
          {" "}
          Read the specification below carefully. Add the test cases one by one.
          A test case ends with 'Next test'. You can continue adding test cases
          after 'Show my result'. <br />
          'Try again' starts a new test design session. &nbsp;&nbsp;You can use
          &nbsp;
          <a href="https://harmony.test-design.org/">Harmony Exercise</a> to
          make action-state test design and execute tests automatedly.
        </p>
        <p class="specification">
          {" "}
          <div style={{ textAlign: "center", fontSize: 20 }}>
            <b> Extra holiday </b>
          </div>
          These requirements are the figment of imagination and not related to
          any real workplace 😊
          <br />
          <b>R1</b> An employee can do overtime (overtime++).
          <br />
          <b>R2</b> Doing overtime three times results in a free day (overtime =
          0, free day++). <br />
          <b>R3</b> An employee can take a free day by pressing – (free day--).{" "}
          <br />
          <b>R4</b> If an employee is late, then one overtime is withdrawn
          (overtime--, if overtime = 0 → free day--, overtime = 2).
          <br />
          <b>R5</b> If an employee takes three free days without lateness, then
          for the subsequent one-time lateness her accepted overtime remains
          unchanged. <br />
          <b>R6</b> If an employee is late and overtime ≤ 0 and free days ≤ 0
          then two overtimes are withdrawn (overtime = -2, free day = 0 →
          overtime = -1, free day = -1). <br />
          <b>R7</b> If the number of free days is reduced to minus three, then
          GAME OVER! <br />
          Test that the code satisfies the requirements. &nbsp;&nbsp;{" "}
        </p>

        <p class="testcases">
          <div>
            {missing.length > 0 ? (
              <span data-harmony-id="Missing test">
                {" "}
                {missing} <br />
              </span>
            ) : (
              <span data-harmony-id="Wrong test">
                {" "}
                {wrongTests[0]} <br />
              </span>
            )}
          </div>
          <span data-harmony-id="result">{result}</span> <br />
          <br />
          Number of extra works:{" "}
          <span
            data-harmony-id="Extra work"
            style={{ color: "mediumaquamarine" }}
          >
            {extraWork}
          </span>{" "}
          <button
            class="button"
            data-harmony-id="extra work + button"
            onClick={() => {
              setExtraWork(extraWork);
              callFunctions("add extra work");
            }}
          >
            <b>add</b>
          </button>
          &nbsp;&nbsp;&nbsp;&nbsp;Number of free days:{" "}
          <span data-harmony-id="holiday" style={{ color: "mediumaquamarine" }}>
            {holidayNumber}
          </span>{" "}
          <button
            class="button"
            data-harmony-id="holiday -"
            onClick={() => {
              setHoliday(holidayNumber);
              callFunctions("spend holiday");
            }}
          >
            <b>-</b>
          </button>
          &nbsp;&nbsp; &nbsp;&nbsp; &nbsp;&nbsp;
          {freeLateness ? (
            <button
              class="button"
              data-harmony-id="Lateness - button"
              style={{ backgroundColor: "yellowgreen" }}
              onClick={() => {
                setFreeLateness(freeLateness);
                //          setLateness(latenessNumber);
                callFunctions("add lateness");
              }}
            >
              <b>add free lateness</b>
            </button>
          ) : (
            <button
              class="button"
              data-harmony-id="Lateness - button"
              onClick={() => {
                setFreeLateness(freeLateness);
                //           setLateness(latenessNumber);
                callFunctions("add lateness");
              }}
            >
              <b>add lateness</b>
            </button>
          )}
          &nbsp;&nbsp; &nbsp;&nbsp;
          {!gameOver && (
            <span>
              {" "}
              &nbsp;&nbsp; &nbsp;&nbsp; &nbsp; &nbsp;&nbsp; &nbsp;&nbsp;
              &nbsp;&nbsp;&nbsp; &nbsp;&nbsp; &nbsp;{" "}
            </span>
          )}
          {!!gameOver && <span style={{ color: "red" }}> GAME OVER </span>}
          <br /> <br />
          <button class="button" data-harmony-id="Next test" onClick={nextTest}>
            {" "}
            Next test{" "}
          </button>{" "}
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          <button class="button" data-harmony-id="Stop" onClick={printResult}>
            {" "}
            Show my result{" "}
          </button>{" "}
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          <button class="button" data-harmony-id="Try again" onClick={tryAgain}>
            {" "}
            Try again{" "}
          </button>{" "}
          {/*
          <button
            class="download"
            data-harmony-id="Download"
            onClick={downloadTasks}
          >
            {" "}
            Download templates{" "}
          </button>{" "}
          <a
            id="downloader"
            href="../templates/pizza_templates.zip"
            download
            hidden
          ></a>
          */}
          <br />
        </p>
      </header>
    </div>
  );
}

export default ExtraHoliday;
